func Execute() error {
	var err error
	rootCmd, err = NewRootCommand()
	if err != nil {
		return err
	}

	// Early agent mode detection from env vars (flag parsing hasn't happened yet).
	// This prevents the explorer TUI from launching when an AI agent is driving the CLI.
	output.InitAgentMode(rootCmd)

	// Auto-launch explorer when invoked with no subcommand from a TTY
	if shouldAutoExplore() {
		return runExplorer(rootCmd)
	}

	return rootCmd.Execute()
}

// shouldAutoExplore returns true when the CLI is invoked with no subcommand
// from an interactive terminal and agent mode is not active.
func shouldAutoExplore() bool {
	if len(os.Args) > 1 {
		return false
	}
	if !term.IsTerminal(int(os.Stdin.Fd())) || !term.IsTerminal(int(os.Stdout.Fd())) {
		return false
	}
	// Agent mode: agents run in PTY terminals but should never get a TUI.
	if output.IsAgentMode() {
		return false
	}
	return true
}

// initExploreCmd registers the "explore" subcommand.
func initExploreCmd(parent *cobra.Command) {
	parent.AddCommand(&cobra.Command{
		Use:   "explore",
		Short: "Interactively browse and run commands",
		Long:  "Launch an interactive command explorer to browse available commands, view their descriptions and flags, and execute them.",
		RunE: func(cmd *cobra.Command, args []string) error {
			// Agent mode: print help instead of launching TUI.
			if output.IsAgentMode() {
				return cmd.Root().Help()
			}
			return runExplorer(cmd.Root())
		},
	})
}

// runExplorer launches the explorer TUI and handles command execution handoff.
func runExplorer(root *cobra.Command) error {
	selectedArgs, err := explorer.Run(root, Version)
	if err != nil {
		return err
	}
	if selectedArgs == nil {
		return nil // user quit
	}
	// Build a fresh command tree and execute the selected command
	freshRoot, err := NewRootCommand()
	if err != nil {
		return err
	}
	freshRoot.SetArgs(selectedArgs)
	return freshRoot.Execute()
}

// globalFlagGroupOrder defines the display order for flag groups in help output.
// Groups without any flags are skipped automatically.
var globalFlagGroupOrder = []string{"Output", "Authentication", "API Parameters", "Server", "Network", "Diagnostics"}

// groupedFlagUsages splits local flags into sections for help display.
// For operation commands (flags with "speakeasy:required"): Required/Optional sections.
// For the root command (flags with "speakeasy:group"): category-based sections.
// Falls back to a flat "Flags:" listing otherwise.
func groupedFlagUsages(flags *pflag.FlagSet) string {
	required := pflag.NewFlagSet("required", pflag.ContinueOnError)
	optional := pflag.NewFlagSet("optional", pflag.ContinueOnError)
	hasGroupAnnotation := false

	flags.VisitAll(func(f *pflag.Flag) {
		if f.Hidden {
			return
		}
		if ann, ok := f.Annotations["speakeasy:required"]; ok && len(ann) > 0 && ann[0] == "true" {
			required.AddFlag(f)
		} else {
			optional.AddFlag(f)
		}
		if _, ok := f.Annotations["speakeasy:group"]; ok {
			hasGroupAnnotation = true
		}
	})

	// Operation commands: Required/Optional sections, with sub-groups when present
	if required.HasFlags() {
		var buf strings.Builder
		buf.WriteString("Required Flags:\n")
		buf.WriteString(required.FlagUsages())
		if optional.HasFlags() {
			if hasGroupAnnotation {
				buf.WriteString("\n")
				buf.WriteString(renderOperationGroups(optional))
			} else {
				buf.WriteString("\nOptional Flags:\n")
				buf.WriteString(optional.FlagUsages())
			}
		}
		return strings.TrimRight(buf.String(), "\n")
	}

	// Grouped flags (root command or operation with only optional grouped flags)
	if hasGroupAnnotation {
		// Check if any groups are in the global order (root-level groups like Output, Server)
		hasGlobalGroup := false
		flags.VisitAll(func(f *pflag.Flag) {
			if ann, ok := f.Annotations["speakeasy:group"]; ok && len(ann) > 0 {
				for _, g := range globalFlagGroupOrder {
					if ann[0] == g {
						hasGlobalGroup = true
					}
				}
			}
		})
		if hasGlobalGroup {
			return renderGroupedFlags(flags, "Flags")
		}
		// Operation-level groups (e.g., Address, Profile)
		return strings.TrimRight(renderOperationGroups(flags), "\n")
	}

	// Fallback: flat listing
	return "Flags:\n" + strings.TrimRight(flags.FlagUsages(), "\n")
}

// groupedGlobalFlagUsages splits inherited (global) flags into category sections
// based on the "speakeasy:group" annotation. Falls back to flat "Global Flags:".
func groupedGlobalFlagUsages(flags *pflag.FlagSet) string {
	hasGroupAnnotation := false
	flags.VisitAll(func(f *pflag.Flag) {
		if f.Hidden {
			return
		}
		if _, ok := f.Annotations["speakeasy:group"]; ok {
			hasGroupAnnotation = true
		}
	})

	if hasGroupAnnotation {
		return renderGroupedFlags(flags, "Global Flags")
	}

	return "Global Flags:\n" + strings.TrimRight(flags.FlagUsages(), "\n")
}

// renderOperationGroups renders optional operation flags grouped by their
// "speakeasy:group" annotation. Groups are shown alphabetically, with
// ungrouped flags under a generic "Optional Flags" header.
func renderOperationGroups(flags *pflag.FlagSet) string {
	groups := make(map[string]*pflag.FlagSet)
	groupOrder := []string{}
	ungrouped := pflag.NewFlagSet("ungrouped", pflag.ContinueOnError)

	flags.VisitAll(func(f *pflag.Flag) {
		if f.Hidden {
			return
		}
		if ann, ok := f.Annotations["speakeasy:group"]; ok && len(ann) > 0 {
			name := ann[0]
			if _, exists := groups[name]; !exists {
				groups[name] = pflag.NewFlagSet(name, pflag.ContinueOnError)
				groupOrder = append(groupOrder, name)
			}
			groups[name].AddFlag(f)
		} else {
			ungrouped.AddFlag(f)
		}
	})

	var buf strings.Builder

	// Show ungrouped optional flags first
	if ungrouped.HasFlags() {
		buf.WriteString("Optional Flags:\n")
		buf.WriteString(ungrouped.FlagUsages())
	}

	// Then show each group
	for _, name := range groupOrder {
		fs := groups[name]
		if !fs.HasFlags() {
			continue
		}
		buf.WriteString("\n" + name + " Flags:\n")
		buf.WriteString(fs.FlagUsages())
	}

	return buf.String()
}

// renderGroupedFlags groups flags by their "speakeasy:group" annotation,
// rendering each group as a separate section with a header. Flags without
// a group annotation are collected under the fallbackHeader section.
func renderGroupedFlags(flags *pflag.FlagSet, fallbackHeader string) string {
	groups := make(map[string]*pflag.FlagSet)
	for _, g := range globalFlagGroupOrder {
		groups[g] = pflag.NewFlagSet(g, pflag.ContinueOnError)
	}
	ungrouped := pflag.NewFlagSet("ungrouped", pflag.ContinueOnError)

	flags.VisitAll(func(f *pflag.Flag) {
		if f.Hidden {
			return
		}
		if ann, ok := f.Annotations["speakeasy:group"]; ok && len(ann) > 0 {
			if fs, exists := groups[ann[0]]; exists {
				fs.AddFlag(f)
				return
			}
		}
		ungrouped.AddFlag(f)
	})

	var buf strings.Builder
	first := true
	for _, name := range globalFlagGroupOrder {
		fs := groups[name]
		if !fs.HasFlags() {
			continue
		}
		if !first {
			buf.WriteString("\n")
		}
		buf.WriteString(name + ":\n")
		buf.WriteString(fs.FlagUsages())
		first = false
	}
	if ungrouped.HasFlags() {
		if !first {
			buf.WriteString("\n")
		}
		buf.WriteString(fallbackHeader + ":\n")
		buf.WriteString(ungrouped.FlagUsages())
	}
	return strings.TrimRight(buf.String(), "\n")
}

// groupedUsageTemplate returns Cobra's default usage template with the local
// and global Flags sections replaced to use grouped rendering.
// Built at runtime via strings.Replace to avoid template delimiter conflicts
// with the code generator's own template engine.
func groupedUsageTemplate() string {
	ob := string([]byte{'{', '{'})
	cb := string([]byte{'}', '}'})
	defaultTmpl := (&cobra.Command{}).UsageTemplate()

	// Replace local flags section
	oldLocal := "Flags:\n" + ob + ".LocalFlags.FlagUsages | trimTrailingWhitespaces" + cb
	replLocal := ob + "groupedFlagUsages .LocalFlags | trimTrailingWhitespaces" + cb
	result := strings.Replace(defaultTmpl, oldLocal, replLocal, 1)

	// Replace global flags section
	oldGlobal := "Global Flags:\n" + ob + ".InheritedFlags.FlagUsages | trimTrailingWhitespaces" + cb
	replGlobal := ob + "groupedGlobalFlagUsages .InheritedFlags | trimTrailingWhitespaces" + cb
	result = strings.Replace(result, oldGlobal, replGlobal, 1)

	return result
}
